// Auth: einfacher Header-Key-Check
const headers = $input.first().json.headers || {};
const apiKey = headers['x-kb-api-key'] || headers['x-kb-api-key'.toLowerCase()] || '';
const expectedKey = $vars.KB_INGEST_API_KEY || '';

if (!expectedKey || apiKey !== expectedKey) {
  throw new Error('Unauthorized: x-kb-api-key fehlt oder falsch');
}

const body = $input.first().json.body || {};
const docId = (body.doc_id || '').replace(/[^a-zA-Z0-9_-]/g, '').slice(0, 64);
const title = (body.title || 'Unbekanntes Dokument').slice(0, 256);
const source = (body.source || 'manual').slice(0, 64);
// file_url: nur interne Hosts erlaubt (SSRF-Schutz)
const fileUrl = body.file_url || '';
const ALLOWED_HOSTS = ['python-nlp-service', 'minio', 'host.docker.internal'];
if (fileUrl) {
  const urlHost = new URL(fileUrl).hostname;
  if (!ALLOWED_HOSTS.includes(urlHost)) {
    throw new Error(`Ungültige file_url: Host '${urlHost}' nicht erlaubt`);
  }
}

if (!docId) throw new Error('doc_id fehlt oder ungültig');

return [{ json: { docId, title, source, fileUrl, text: (body.text || '').slice(0, 50000) } }];

// Entweder extrahierter PDF-Text oder direkt übermittelter Text
let text = '';
let meta = {};
try {
  const extracted = $('NLP PDF-Extraktion').first().json;
  text = (extracted.text || '').slice(0, 50000);
  meta = extracted.metadata || {};
} catch {
  // Kein URL-Pfad → Text direkt aus Request
  text = $('Request validieren').first().json.text || '';
}

const req = $('Request validieren').first().json;
return [{
  json: {
    docId: req.docId,
    title: req.title,
    source: req.source,
    text: text,
    metadata: meta
  }
}];

const merged = $('Text zusammenführen').first().json;
const entities = $('NLP Analyse (Entitäten)').first().json.entities || [];
const embedding = $('Embedding erstellen').first().json.embedding || [];

return [{
  json: {
    docId: merged.docId,
    title: merged.title,
    source: merged.source,
    text: merged.text,
    entities: entities,
    embedding: embedding
  }
}];

